SELECT AVG(number_of_birds) AS average_birds_observed
FROM observations
WHERE user_id = (SELECT user_id FROM user_access_logs WHERE log_id = 1);

SELECT species_name 
FROM species 
WHERE noticeability = '**' AND conservation_status = 'Vulnerable';

SELECT species_name
FROM species
WHERE average_lifespan > (SELECT average_lifespan FROM species WHERE species_name = 'Black-throated Gray Warbler');

SELECT s.species_name, s.average_lifespan
FROM species s
WHERE s.species_id NOT IN (
  SELECT o.species_id 
  FROM observations o
);

SELECT MAX(average_lifespan) AS max_lifespan
FROM species
WHERE habitat = 'Wetlands and rivers';
